algorithm:
Greedy insertion with incremental regret heuristic: evaluate all feasible insertions across existing non-empty assigns first using marginal cost increase, then try empty/new assigns if needed, always falling back to direct addition to a fresh assign if absolutely necessary.}
func InsertShips(dispatch Dispatch, oris, dess []Station, total_ship int) Dispatch {
	type candidate struct {
		assignIdx int
		costDelta float64
		valid     bool
	}
	totalOrders := len(oris)
	if totalOrders == 0 {
		dispatch.RenewnTotalCost()
		return dispatch
	}
	for orderID := 0; orderID < totalOrders; orderID++ {
		bestCandidate := candidate{valid: false, costDelta: 1e18}
		fallbackAssignIdx := -1
		for ai := 0; ai < dispatch.AssignsLen; ai++ {
			origCost := dispatch.Assigns[ai].Cost
			if dispatch.Assigns[ai].AddShip(total_ship+orderID, oris[orderID], dess[orderID]) {
				dispatch.Assigns[ai].GenRoute()
				newCost := dispatch.Assigns[ai].Cost
				if newCost >= 0 {
					delta := newCost - origCost
					if delta < bestCandidate.costDelta {
						bestCandidate = candidate{assignIdx: ai, costDelta: delta, valid: true}
					}
				}
				dispatch.Assigns[ai].RemoveShip(total_ship + orderID)
				dispatch.Assigns[ai].GenRoute()
			}
		}
		inserted := false
		if bestCandidate.valid {
			dispatch.Assigns[bestCandidate.assignIdx].AddShip(total_ship+orderID, oris[orderID], dess[orderID])
			dispatch.Assigns[bestCandidate.assignIdx].GenRoute()
			inserted = true
		}
		if !inserted {
			for ai := dispatch.AssignsLen; ai < MAXASSIGNS; ai++ {
				if dispatch.Assigns[ai].AddShip(total_ship+orderID, oris[orderID], dess[orderID]) {
					dispatch.Assigns[ai].GenRoute()
					if dispatch.Assigns[ai].Cost >= 0 {
						dispatch.AssignsLen = ai + 1
						inserted = true
						break
					} else {
						dispatch.Assigns[ai].RemoveShip(total_ship + orderID)
						dispatch.Assigns[ai].GenRoute()
					}
				}
				fallbackAssignIdx = ai
			}
		}
		if !inserted && fallbackAssignIdx >= 0 && fallbackAssignIdx < MAXASSIGNS {
			if dispatch.Assigns[fallbackAssignIdx].AddShip(total_ship+orderID, oris[orderID], dess[orderID]) {
				dispatch.Assigns[fallbackAssignIdx].GenRoute()
				if dispatch.Assigns[fallbackAssignIdx].Cost >= 0 {
					if fallbackAssignIdx >= dispatch.AssignsLen {
						dispatch.AssignsLen = fallbackAssignIdx + 1
					}
					inserted = true
				}
			}
		}
	}
	dispatch.RenewnTotalCost()
	return dispatch

